const attachments = items[0].binary || {};

const files = Object.keys(attachments).map(key => {
  return {
    json: {
      fileName: key
    },
    binary: {
      data: attachments[key]
    }
  };
});

return files;

parameters.jsCode:
return items.map(item => {
  let raw = item.json.output;

  try {
    // Step 1: Clean string (remove line breaks)
    raw = raw.replace(/\\n/g, '');

    // Step 2: Parse JSON string
    const parsed = JSON.parse(raw);

    return {
      json: parsed
    };

  } catch (err) {
    return {
      json: {
        success: false,
        error: "JSON_PARSE_ERROR",
        raw_output: item.json.output
      }
    };
  }
});

